import{_ as u,G as s,c,o as n,a6 as i,m as t,b as m,J as r,w as e,a,ao as k}from"./chunks/framework.CS_FrCij.js";const p="/assets/enkelsutur1.B-hW9Yb0.gif",h="/assets/st%C3%A5endemadrass.BAMDP96T.gif",b="/assets/liggandemadrass.IID5CGv2.gif",f="/assets/fortl%C3%B6pande.DS8eDn43.gif",v="/assets/cornerstitchy.CgArR7n5.gif",_="/assets/cornerstitchv.Bf8MrK8O.gif",y="/assets/vshape.B1qilTWW.gif",A="/assets/steristrip.W_yY2nsc.gif",S="/assets/vattent%C3%A4ttpl%C3%A5ster.0oEKVK0s.gif",T="/assets/absorberandef%C3%B6rband.CEmPgGp9.gif",x="/assets/sipro.BauUgEP4.gif",D="/assets/exufiber.De8CfwfH.gif",E="/assets/mepilextransfer.BO33-sDr.gif",ot=JSON.parse('{"title":"2. Handläggning","description":"Översikt och handläggning av traumatiska sår, klassificering, behandling och tips för kliniker.","frontmatter":{"title":"2. Handläggning","description":"Översikt och handläggning av traumatiska sår, klassificering, behandling och tips för kliniker.","layout":"doc","next":{"text":"3. Antibiotika","link":"sarvard/antibiotika"}},"headers":[],"relativePath":"sarvard/handlaggning.md","filePath":"sarvard/handlaggning.md","lastUpdated":1777710484000}'),I={name:"sarvard/handlaggning.md"},C=i('<h1 id="handlaggning-pa-akuten" tabindex="-1">HANDLÄGGNING PÅ AKUTEN <a class="header-anchor" href="#handlaggning-pa-akuten" aria-label="Permalink to &quot;HANDLÄGGNING PÅ AKUTEN&quot;">​</a></h1><h2 id="anamnes" tabindex="-1">ANAMNES <a class="header-anchor" href="#anamnes" aria-label="Permalink to &quot;ANAMNES&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">För att kunna prognosticera sårets läkningsförmåga och infektionsrisken behöver man ta en god sjukdomshistoria. Detta kan vara avgörande för vilka åtgärder man väljer.</p></div><h3 id="tidigare-nuvarande-sjukdomar-aktuellt" tabindex="-1">Tidigare / nuvarande sjukdomar / aktuellt <a class="header-anchor" href="#tidigare-nuvarande-sjukdomar-aktuellt" aria-label="Permalink to &quot;Tidigare / nuvarande sjukdomar / aktuellt&quot;">​</a></h3><ul><li>Perifer kärlsjukdom (ffa diabetes och claudicatio)</li><li>Immunosupprimerad</li><li>Främmande föremål</li><li>Tetanusstatus</li></ul><h3 id="riskfaktorer-som-okar-infektionsrisk" tabindex="-1">Riskfaktorer som ökar infektionsrisk <a class="header-anchor" href="#riskfaktorer-som-okar-infektionsrisk" aria-label="Permalink to &quot;Riskfaktorer som ökar infektionsrisk&quot;">​</a></h3><ul><li>Efter 6 - 12 timmar har man traditionellt betraktat ett sår som klass 4. Detta är omdebatterat idag då sårrengöring blivit så mycket bättre.</li><li>Krosskada: Ofta rejält skadad vävnad utöver huden. Minskat blodflöde till sårkanterna. Ökar bakteriebördan upp till 100 gånger.</li><li>&gt; 5 cm lång sårskada</li><li>Djup sårskada (&gt; 6 mm; man kan se subcutis)</li><li>&gt; 65 år</li><li>Höghastighetsprojektil</li><li>Kontaminering: Saliv, jord, feces.</li><li>Punktionsskada (bett, tagg)</li></ul><div class="warning custom-block"><p class="custom-block-title">VIKTIGA BEAKTANDEN</p><ul><li>Primärsutur ska ske inom 8 - 12h. Data pekar dock på att timingen inte är lika viktig som dom andra riskfaktorerna eftersom rengöring och debridering blivit så pass bra. UpToDate tycker det går bra upp till 18 timmar.</li><li>Fina och rena ansiktssår kan primärförslutas &gt; 24h efter skadan</li></ul></div><h3 id="sarlokalisation" tabindex="-1">Sårlokalisation <a class="header-anchor" href="#sarlokalisation" aria-label="Permalink to &quot;Sårlokalisation&quot;">​</a></h3><p>Sårlokalisation är en av dom viktigaste faktorerna vid bedömning av infektionsrisk. Lår och framförallt underben har högst risk då kroniska sjukdomar ofta skadar kärl och hudstrukturen kring ankel och underben. Dåliga förutsättningar för sårläkning. Detta gör det särskilt riskabelt om kontamination föreligger.</p>',10),N=t("thead",null,[t("tr",null,[t("th",{style:{"text-align":"left"}},"Lokalisation"),t("th",{style:{"text-align":"center"}},"Infektionsrisk efter suturering")])],-1),P=t("tr",null,[t("td",{style:{"text-align":"left"}},"Ansikte + skalp"),t("td",{style:{"text-align":"center"}},"< 4%")],-1),q=t("tr",null,[t("td",{style:{"text-align":"left"}},"Torso + andra extremiteter"),t("td",{style:{"text-align":"center"}},"> 10%")],-1),j=t("td",{style:{"text-align":"left"}},"Lår/underben",-1),B={style:{"text-align":"center"}},L=t("b",null,"> 20%",-1),R=i('<p>Risk för infektion: Underben &gt; lår &gt; armar &gt; fötter &gt; bröst &gt; rygg &gt; ansikte &gt; skalp</p><div class="tip custom-block"><p class="custom-block-title">VÅGMÄSTARE</p><p>Det är den sammanvägda bedömningen med alla dessa faktorer som ska ligga till grund för klinikern om såret ska förslutas och om antibiotika är aktuellt.</p></div><h2 id="status-radiologi" tabindex="-1">STATUS &amp; RADIOLOGI <a class="header-anchor" href="#status-radiologi" aria-label="Permalink to &quot;STATUS &amp; RADIOLOGI&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">ATT FÖRSTÅ SÅRET</p><p>Ibland kan det vara klurigt att förstå såret och se den för vad den är; framförallt om den blöder och ändrar skepnad hela tiden. Hemostas kan därför blottgöra och förenkla såråskådningen.</p><p>På en sårskadad extremitet kan en blodtrycksmanschett användas med fördel proximalt om såret samtidigt som man höjer extremiteten 1-2 minuter. Manschetten kan vara på 2 timmar om man så önskar, men sannolikt så kommer patienten vara i så pass mycket smärta att det är självbegränsande.</p></div>',4),V={class:"tip custom-block"},G=t("p",{class:"custom-block-title"},"FRÄMMANDE FÖREMÅL",-1),O=t("p",null,"Om man misstänker att ett föremål tagit sig in på djupet men man kan inte se eller palpera den så kan man med fördel nyttja olika typer av radiologi. Valet av bildmodalitet blir beroende på vad för objekt man misstänker.",-1),K=t("b",null,"SLÄTRÖNTGEN",-1),M=t("br",null,null,-1),F=t("b",null,"SKIKTRÖNTGEN, CT ",-1),H=t("br",null,null,-1),U=t("b",null,"ULTRALJUD",-1),w=t("br",null,null,-1),J=i('<h2 id="handlaggning" tabindex="-1">HANDLÄGGNING <a class="header-anchor" href="#handlaggning" aria-label="Permalink to &quot;HANDLÄGGNING&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Nu kommer vi till den viktigaste delen i artikeln, nämligen hur vi stegvis handlägger ett sår.</p></div><h3 id="oversikt" tabindex="-1">Översikt <a class="header-anchor" href="#oversikt" aria-label="Permalink to &quot;Översikt&quot;">​</a></h3>',3),W=i('<h3 id="lokalanestesi" tabindex="-1">Lokalanestesi <a class="header-anchor" href="#lokalanestesi" aria-label="Permalink to &quot;Lokalanestesi&quot;">​</a></h3><h4 id="val-av-lokalanestetikum" tabindex="-1"><br>Val av lokalanestetikum <a class="header-anchor" href="#val-av-lokalanestetikum" aria-label="Permalink to &quot;&lt;br&gt;Val av lokalanestetikum&lt;/br&gt;&quot;">​</a></h4><div class="info custom-block"><p class="custom-block-title">SÅRSKADOR PÅ AKUTEN</p><p>MEPIVAKAIN (<strong>Carbocain®</strong>)<br> LIDOCAIN (<strong>Xylocain®</strong>)</p></div><table><thead><tr><th style="text-align:left;">Typ</th><th style="text-align:left;">Anslagstid</th><th style="text-align:left;">Duration</th><th style="text-align:left;">Rimlig dos</th></tr></thead><tbody><tr><td style="text-align:left;">Mepivakain</td><td style="text-align:left;"><ul><li>Sekunder</li></ul></td><td style="text-align:left;"><ul><li>1,5 - 4 h</li></ul></td><td style="text-align:left;"><ul><li>1-20 ml (10 mg/ml)</li><li>5 mg/kg (maxdos)</li></ul></td></tr><tr><td style="text-align:left;">Lidokain</td><td style="text-align:left;"><ul><li>Sekunder</li></ul></td><td style="text-align:left;"><ul><li>20-60 minuter</li><li>2-6 h (adrenalin)</li></ul></td><td style="text-align:left;"><ul><li> 5-40 ml (10 mg/ml)</li><li>4 mg/kg (maxdos)</li><li>7 mg/kg (adrenalin)</li></ul></td></tr></tbody></table><details class="details custom-block"><summary>VARFÖR MEPIVAKAIN &gt; LIDOKAIN</summary><ul><li>Liknande anslagstid</li><li>Längre duration</li><li>Samma potens</li><li>Mindre toxicitet</li><li>Ej beroende av adrenalin i lika hög grad</li></ul></details><div class="tip custom-block"><p class="custom-block-title">BUFFRA</p><p>Carbocain är löst i en låg pH-lösning (pH 4,5 - 6). Agerar antimikrobiellt. Detta betyder också att det gör extra ont vid injektion. Man kan tillsätta 1-2 ml 0,6 M Natriumbikarbonat till 10 ml carbocain.</p></div><div class="danger custom-block"><p class="custom-block-title">ADRENALIN</p><p>Fördröjer läkningsperioden. Ökar infektionsrisk. Om högrisksår med omfattande vävnadsskada: överväg avstå adrenalin.</p></div><h4 id="allergi" tabindex="-1"><br>Allergi <a class="header-anchor" href="#allergi" aria-label="Permalink to &quot;&lt;br&gt;Allergi&lt;/br&gt;&quot;">​</a></h4><div class="info custom-block"><p class="custom-block-title">2 familjer inom lokalanestesi</p><ul><li>Amider (Lidokain, Mepivakain, Bupivakain)</li><li>Estrar (Prokain, Tetrakain, Benzokain)</li></ul></div><div class="warning custom-block"><p class="custom-block-title">KORSREAGERAR INTE</p><p>Vid osäkerhet om allergi, injicera 0,1 ml och utvärdera efter 30min</p></div><h4 id="injektionsteknik" tabindex="-1"><br>Injektionsteknik <a class="header-anchor" href="#injektionsteknik" aria-label="Permalink to &quot;&lt;br&gt;Injektionsteknik&lt;/br&gt;&quot;">​</a></h4><details class="details custom-block"><summary>Skolans misslyckande</summary><p>Av någon bisarr orsak missade jag PM:et där det skall ha framgått att lokalanestesin INTE ska infiltreras i epidermis. Tyckte alltid det var lite märkligt att jag ofta jobbade mot så djävulskt mycket motstånd vid injektionsmomentet. Rent anatomiskt är detta mycket enkelt att förklara. Som beskrivet i denna artikels första del <a href="#anatomi">Anatomi</a>, finner vi sensoriska nervstruktur i dermis/subcutis och INTE i epidermis. Av mycket logiska skäl innebär detta givetvis att vi skall infiltrera djupa delen av dermis (mindre spridning) alternativt ytliga delen av subcutis (större spridning).</p></details><p>Ett bra nålval som har ett balanserat injektionsflöde (smärta kontra hastighet) är en 23 Gauge nål. I svenska termer motsvarar detta en blå nål. .</p><p>När vi har en sårskada framför oss finns det två tillvägagångssätt. Antingen betraktas såret tillräkligt rent för att vi ska kunna injicera direkt i sårkanterna (förslagsvis ytliga delen av subcutis). Detta kommer vara majoriteten av sår och är mindre smärtsamt. I annat fall kan såret vara så skitigt att man kan riskera dra med sig smuts in i vävnaden. Detta vill vi absolut inte göra eftersom vi i princip gödslar med potentiellt infektionsmaterial.</p><p>Om du sticker perkutant (via huden), se till att denna är rengjord, förslagsvis med tvål och vatten. Om du är lite ångestladdad kan man även, MED FÖRSIKTIGTHET, använda klorhexidin på frisk hud. Klorhexidin skadar öppna sårytor och förlänger läkning. Sen gör det sinnessjukt ont för patienten</p><p>En generellt bra teknik är att man sticker in hela vägen längst med sårkanten tills man når basen av nålen. Därefter aspirerar man, backar långsamt, samtidigt som man injicerar lokalanestesi. Djupet bör vara ungefär 5 mm för att adekvat nå rätt del av dermis/subcutis.</p><h4 id="kort-om-finger-tablockad-och-adrenalin" tabindex="-1"><br>Kort om finger-tåblockad och adrenalin <a class="header-anchor" href="#kort-om-finger-tablockad-och-adrenalin" aria-label="Permalink to &quot;&lt;br&gt;Kort om finger-tåblockad och adrenalin&lt;/br&gt;&quot;">​</a></h4><div class="info custom-block"><p class="custom-block-title">Sannolikt inte farlig</p><p>Tes: Vasokonstriktion av endarterioler -&gt; ischemi<br> Case studies från handkirurgi: Säkert med försiktig monitorering. Reverseras med lokalinjektion 0,5 - 2 mg subkutant phentolamin alternativt topikal nitroglycerin.</p><p>Om det är svårt att ha blodfritt arbetsfält kan man överväga att tornikera fingret/tån på dess bas med exempelvis ett bandage.</p></div><h3 id="sarhantering" tabindex="-1">Sårhantering <a class="header-anchor" href="#sarhantering" aria-label="Permalink to &quot;Sårhantering&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Efter man har framgångsrikt välsignat området med lokal analgesi kan sårtvätt börja. Plåga inte patienten i onödan.</p></div><h4 id="debridering-och-sartvatt" tabindex="-1"><br>Debridering och sårtvätt <a class="header-anchor" href="#debridering-och-sartvatt" aria-label="Permalink to &quot;&lt;br&gt;Debridering och sårtvätt&lt;/br&gt;&quot;">​</a></h4><div class="info custom-block"><p class="custom-block-title">DEBRIDERING</p><p>Debridering är i särklass ett av dom viktigaste momenten i sårvård. Om kroppsfrämmande föremål och partiklar missas i sår finns en skälig risk att ingen adekvat läkning sker samtidigt som infektionsrisken ökar dramatiskt. Utöver detta kan sårläkning ske på ett ofördelaktigt sätt vilket förändrar anatomin på ett estetiskt eller funktionellt olämpligt vis.</p></div><div class="tip custom-block"><p class="custom-block-title">SÅRTVÄTT</p><p>Efter man plockat bort större och uppenbara föroreningar kommer nästa viktiga steg, vilket är att man tvättar rent såret. Här kan man med fördel använda ljummet kranvatten blandat med tvål. Effektmässigt är kranvatten jämförbart med koksalt. Kranvatten är i princip gratis och lättillgängligt. Koksalt kan reserveras till kirurgiskt sterila sår; sårskador på akuten betraktas redan som kontaminerade.</p><p>Om man inte fysiskt skrubbar i såret ska ett spoltryck på 7 Psi uppnås, detta för att säkerställa att skräp och mikroorganismer sköljs bort utan att skada vävnaden ytterliggare. Ett enkelt sätt att säkerställa att man spolar rätt är att ansluta en 30 mL spruta med en 18G nål (rosa pvk eller röd uppdragningskanyl). Här rekommenderar jag att man använder PVK:n så man undviker skärande våld.</p></div>',23),Y={class:"warning custom-block"},$=t("p",{class:"custom-block-title"},"HÅR",-1),z=t("p",null,"Hår är något av ett gissel vad gäller sårskador. Hamnar i såret, är i vägen när man suturerar, och gör det onödigt svårt.",-1),X=t("p",null,"OKEJ: Vaselin/oljig substans på sårkant = agerar hårprodukt.",-1),Q=i('<h3 id="sarforslutning" tabindex="-1">Sårförslutning <a class="header-anchor" href="#sarforslutning" aria-label="Permalink to &quot;Sårförslutning&quot;">​</a></h3><h4 id="primarforslutning" tabindex="-1"><br>Primärförslutning <a class="header-anchor" href="#primarforslutning" aria-label="Permalink to &quot;&lt;br&gt;Primärförslutning&lt;/br&gt;&quot;">​</a></h4><ul><li>Ej infekterat</li><li>Tid &lt; 12-18 h (rena ansiktssår upp till 48h)</li></ul><h4 id="fordrojd-primarforslutning" tabindex="-1">Fördröjd primärförslutning <a class="header-anchor" href="#fordrojd-primarforslutning" aria-label="Permalink to &quot;Fördröjd primärförslutning&quot;">​</a></h4>',4),Z=i('<div class="info custom-block"><p class="custom-block-title">Bra att veta</p><p>Samma läkningstid men dramatiskt reducerad infektionsrisk. Om extremitet, omlägges med skena. Oklart huruvida packning är fördelaktigt eller ej. Orsakar mer smärta utan uppenbar vinst. Återbesök 24h för sårkontroll och omläggningsbyte.</p></div><div class="danger custom-block"><p class="custom-block-title">ANTIBIOTIKA GES INTE TILL DESSA SÅR</p></div><h3 id="suturtyper" tabindex="-1">Suturtyper <a class="header-anchor" href="#suturtyper" aria-label="Permalink to &quot;Suturtyper&quot;">​</a></h3><p>Vi använder i första hand syntetiska suturer eftersom dom är till sin yta glatt (låg friktion) men har också som regel mycket låg vävnadsreaktivitet. Detta gör dem lätta att knyta men lite svårare att hantera eftersom de gärna vill tillbaks till sin ursprungsform - &quot;suture memory&quot;. Det är viktigt man knyter med god teknik för att de inte ska gå upp.</p><details class="details custom-block"><summary>ETHILON</summary><ul><li>Nylon (polyamide)</li><li>Monofilament</li><li>Icke-absorberbar</li><li>Billig och i särklass den vanligaste suturen vi använder på akuten.</li></ul></details><details class="details custom-block"><summary>PROLENE</summary><ul><li>Prolene (polypropylene)</li><li>Betraktas som den förfinade Ethilonsuturen</li><li>Mer slitstark, håller sin form, och lämpar sig för långvarig användning in vivo</li><li>Sällan indicerad på akuten</li><li>Dyrare per sutur</li></ul></details><details class="details custom-block"><summary>VICRYL</summary><ul><li>Polyglactin (vicryl)</li><li>Flätad multifilament -&gt; Hög draghållfasthet</li><li>Svagt &quot;suture memory&quot;</li><li>30% svagare efter 2 veckor; 50% svagare efter 3 veckor; 75% svagare efter 4 veckor; absorberad efter 2 månader</li></ul></details><h3 id="suturering" tabindex="-1">Suturering <a class="header-anchor" href="#suturering" aria-label="Permalink to &quot;Suturering&quot;">​</a></h3><p>Här inkluderas de vanligaste och mest användbara sårförslutningsverktygen på en akutmottagning.</p><h4 id="suturer" tabindex="-1">Suturer <a class="header-anchor" href="#suturer" aria-label="Permalink to &quot;Suturer&quot;">​</a></h4><div class="warning custom-block"><p class="custom-block-title">Surgeon&#39;s knot</p><p>Samtliga suturer låses med 2-1-1 teknik. Första vändningen bestämmer suturens styrka. 2 slag för att övervinna &quot;suture memory&quot;. Andra låser knuten. Tredje för säkerhetsmarginal. Demonstrationsvideos på samtliga suturer.</p></div><details class="details custom-block"><summary>Enkelsutur</summary><p><img src="'+p+'" alt="enkelsutur"><em>Lämpar sig till i princip alla sår. Du kommer använda denna sutur i &gt; 90% av såren du stöter på.</em></p></details><details class="details custom-block"><summary>Stående madrass</summary><p><img src="'+h+'" alt="ståendemadrass"><em>Vid djupare sår där resorberbartråd inte behövs.</em></p></details><details class="details custom-block"><summary>Liggande madrass</summary><p><img src="'+b+'" alt="liggandemadrass"><em>Vid sår där man vill sprida ut suturtensionen för att undvika att man drar igenom svag och skör hud. Lämpar sig bra för V-formade sår.</em></p></details><details class="details custom-block"><summary>Fortlöpande utan låsning</summary><p><img src="'+f+'" alt="fortlöpande"><em>Kan används för raka lacerationer med låg infektionsrisk. Sparar tid. Nackdel är att man måste klippa bort hela tråden vid minsta problem som kräver sårrevision.</em></p></details><details class="details custom-block"><summary>Y-sår</summary><p><img src="'+v+'" alt="cornerstitchy"><em>Corner stitch.</em></p></details><details class="details custom-block"><summary>V-sår</summary><p><img src="'+_+'" alt="cornerstitchv"><em>Corner stitch.</em></p></details><details class="details custom-block"><summary>V-sår med liggande madrass</summary><p><img src="'+y+'" alt="cornerstitch2"><em>Liggande madrass istället för corner stitch.</em></p></details><div class="info custom-block"><p class="custom-block-title">STAPLING</p><p>Fungerar bra på fina och hyfsat raka lacerationer. Tidsvinst och billigare. Lägre infektionsrisk.</p></div><div class="tip custom-block"><p class="custom-block-title">PRAKTISK PATIENTINFORMATION SUTUR</p><ul><li>Duscha går bra</li><li>Bada inte -&gt; ökar risk för infektion</li><li>Skrubba inte</li><li>Suturer tas bort hos distriktssköterska, sårlokalisation avgör tid</li><li>Informera om infektion</li></ul></div><h4 id="suturtabell" tabindex="-1">Suturtabell <a class="header-anchor" href="#suturtabell" aria-label="Permalink to &quot;Suturtabell&quot;">​</a></h4><table><thead><tr><th style="text-align:left;">Lokal</th><th style="text-align:left;">Storlek</th><th style="text-align:center;">Längd (dagar)</th></tr></thead><tbody><tr><td style="text-align:left;">Ansikte</td><td style="text-align:left;">4-0, 5-0</td><td style="text-align:center;">5-7</td></tr><tr><td style="text-align:left;">Huvud, skalp</td><td style="text-align:left;">3-0</td><td style="text-align:center;">7-10</td></tr><tr><td style="text-align:left;">Thorax, buk, övre extr</td><td style="text-align:left;">3-0, 4-0</td><td style="text-align:center;">10-12</td></tr><tr><td style="text-align:left;">Rygg, nedre extr</td><td style="text-align:left;">3-0, 4-0</td><td style="text-align:center;">14-17</td></tr></tbody></table><h4 id="limning" tabindex="-1">Limning <a class="header-anchor" href="#limning" aria-label="Permalink to &quot;Limning&quot;">​</a></h4><details class="details custom-block"><summary>DermaFlex</summary><p>Låg tröskel för användning på barn. Sannolikt underanvänt på akuten. Lämpar sig på följande:</p><ul><li>&lt; 6 cm sår</li><li>Sår med god hemostas, limmet fäster annars inte</li><li>Gärna inte djupare än 1 cm</li><li>Sårkanterna måste ha låg spänning, annars hög risk för att limmet släpper under läkning</li><li>Låg dynamisk plats, ie INTE ÖVER LEDER, händer</li><li>Stelnar efter 95 sekunder</li><li>Försvinner efter 7 dagar</li><li>LIM + SteriStrip är en kombination guld värd. Slitningssår, exempelvis hos äldre med tunn kortisonbehandlad hud så kan detta vara ett mycket bra alternativ.</li></ul></details><div class="tip custom-block"><p class="custom-block-title">PRAKTISK PATIENTINFORMATION LIM</p><ul><li>Duscha går bra</li><li>Bada inte -&gt; ökar risk för infektion och kan lösgöra limmet</li><li>Skrubba inte -&gt; risk för att mekaniskt skrubba bort limmet</li><li>Försvinner av sig självt efter 7 dagar</li><li>Informera om infektion</li></ul></div><h3 id="omlaggning" tabindex="-1">OMLÄGGNING <a class="header-anchor" href="#omlaggning" aria-label="Permalink to &quot;OMLÄGGNING&quot;">​</a></h3><p>Med tanke på att vi får nästan noll utbildning vad gäller såromläggning utgör detta alltför ofta ett problem när omvårdnadspersonal frågar &quot;experten&quot; vad för typ av förband som ska användas för respektive sår. Dessa förband finns tillgängliga på akuten. Kortfattade videodemonstrationer.</p><div class="tip custom-block"><p class="custom-block-title">PRINCIPER</p><p>Skapa optimal sårläkningsmiljö -&gt; värna om makrofager och fibroblaster</p><ul><li>Omläggning ska hålla såret fuktigt, goda förutsättningar för epitelialisering. Ett torrt sår bildar ett hårt och tjockt callus med signifikant minskad epitelialisering.</li><li>Vid vätskande sår och omläggning som &quot;fångar&quot; trans/exsudat uppstår maceration som hämmar sårläkning och ökar infektionsrisk. Hornlagret blir överhydrerat, svullet, och försvagat rent strukturellt -&gt; Dålig såradaptation. Detta förlänger sårläkning, ökar smärtan, och förstorar såret.</li><li>Behöver vara permeabel för gas då O2 är essentiel för epitelialisering</li></ul></div><details class="details custom-block"><summary>Sårtejp &quot;SteriStrip&quot;</summary><p>Vävnadsstödjande. Funkar till dom flesta sårskadorna. Kan utgöra primärbehandling hos barn och äldre. <img src="'+A+'" alt="steristrip"></p></details><details class="details custom-block"><summary>Lättabsorberande vattentätt plåster</summary><p>Standardförband. Lämpar sig till majoriteten av sårskador. Ej adekvat vid ordentligt vätskande sår. Fångar vätska och orsakar maceration. <img src="'+S+'" alt="vattentättplåster"></p></details><details class="details custom-block"><summary>Absorberande förband</summary><p>Används på sår som förväntas vätska större volymer som exempelvis:</p><ul><li>Venösa bensår</li><li>Diabetesrelaterade bensår</li><li>Brännskador, delhudengagemang</li><li>Sår vid lymfödem</li></ul><p>Viktigt att undvika maceration. <img src="'+T+'" alt="absorberandeförband"></p></details><details class="details custom-block"><summary>Silicone would contact layer &quot;Sipro&quot;</summary><p>Används på större sårytor med skör hud där förbandet riskerar att torka in i såret. Detta gelliknande förband läggs som en skyddande barriär ovanpå såret varvid förbandet läggs ovanpå. Transporterar exusdat effektivt till förbandet. Kan vara på så länge den släpper igenom vätska <img src="'+x+'" alt="sipro"></p></details><h4 id="specialforband" tabindex="-1">Specialförband <a class="header-anchor" href="#specialforband" aria-label="Permalink to &quot;Specialförband&quot;">​</a></h4><details class="details custom-block"><summary>Gel fibre dressing &quot;Exufiber&quot;</summary><p>Gelbildande förband som lämpar sig till kraftigt vätskande sår som typiskt ses vid diabetes, tryck, och kirurgiska sår. Vid vätskekontakt omvandlas förbandet till en gel som agerar som en inkapslande vätskebarriär. Passar till djupa sårhålor. <img src="'+D+'" alt="exufiber"></p></details><details class="details custom-block"><summary>Vätsketransporterande &quot;Mepilex transfer&quot;</summary><p>Transporterar bort stor mängd vätska till täckförbandet. Förhindrar maceration. <img src="'+E+'" alt="mepilextransfer"></p></details>',35);function tt(at,et,rt,it,st,lt){const o=s("re"),l=s("ye"),d=s("Mermaid"),g=s("gr");return n(),c("div",null,[C,t("table",null,[N,t("tbody",null,[P,q,t("tr",null,[j,t("td",B,[r(o,null,{default:e(()=>[L]),_:1})])])])]),R,t("div",V,[G,O,t("ul",null,[t("li",null,[r(l,null,{default:e(()=>[K]),_:1}),a(),M,a(" Metall 99%; Glas 75%; Trä 7%.")]),t("li",null,[r(l,null,{default:e(()=>[F]),_:1}),H,a("Ser alla typer av främmande föremål vilket gör den golden standard. De uppenbara negativa aspekterna är strålning och kostnad.")]),t("li",null,[r(l,null,{default:e(()=>[U]),_:1}),w,a("Bra men kan ibland ge dåligt resultat pga små föremål, luft, ödem, pus, blod, kalcifieringar.")])])]),J,(n(),m(k,null,{default:e(()=>[r(d,{id:"mermaid-191",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%22Suturkr%C3%A4vande%20s%C3%A5r%22%5D%20--%3E%20B%5B%22Lokalanestesi%22%5D%0A%20%20%20%20B%20--%3E%20C%5B%22Debridering%2C%20reng%C3%B6ring%2C%20s%C3%A5radaptation%22%5D%0A%20%20%20%20C%20--%3E%20D%5B%22Suturering%22%5D%0A%20%20%20%20D%20--%3E%20E%5B%22Bra%20s%C3%A5radaptering%3F%22%5D%0A%20%20%20%20E%20--%3E%7CJa%7C%20Bra_S%C3%A5radaptation%5B%22Oml%C3%A4ggning%22%5D%0A%20%20%20%20E%20--%3E%7CNej%7C%20D%C3%A5lig_S%C3%A5radaptation%5B%22%C3%96verv%C3%A4g%20s%C3%A4tta%20om%20stygn%22%5D%0A%20%20%20%20D%C3%A5lig_S%C3%A5radaptation%20--%3E%20Bra_S%C3%A5radaptation%0A%20%20%20%20%0A"})]),fallback:e(()=>[a(" Loading... ")]),_:1})),W,t("div",Y,[$,z,t("p",null,[a("⭐ "),r(g,null,{default:e(()=>[a("BÄST:")]),_:1}),a(" Trimmer/sax.")]),X,t("p",null,[a("🔴 "),r(o,null,{default:e(()=>[a("DÅLIG:")]),_:1}),a(" Rakhyvel. Skadar hårfolliklars infundibulum vilket skapar enkel bakterieacess. Infektionsrisk ökar 9-faldigt.")])]),Q,(n(),m(k,null,{default:e(()=>[r(d,{id:"mermaid-399",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%22S%C3%A5r%20%E2%AC%86%EF%B8%8F%20infektionsrisk%22%5D%20--%3E%20B%5B%22F%C3%B6rdr%C3%B6jd%20prim%C3%A4rf%C3%B6rslutning%22%5D%0A%20%20%20%20B%20--%3E%20C%5B%22%0A-%20Debridering%3Cbr%3E%0A-%20Reng%C3%B6ring%22%5D%0A%20%20%20%20C%20--%3E%20D%5B%22%0A-%20L%C3%A4mnas%20%C3%B6ppen%0A-%20Daglig%20spolning%0A-%20Oml%C3%A4ggningar%22%5D%0A%20%20%20%20D%20--%3E%20%7C3-5%20dagar%7C%20E%5B%22Prim%C3%A4rf%C3%B6rslutning%22%5D%20%20%0A"})]),fallback:e(()=>[a(" Loading... ")]),_:1})),Z])}const dt=u(I,[["render",tt]]);export{ot as __pageData,dt as default};
